+    value,
+    [&](const std::string& mode) -> failure_or<std::optional<pagination_spec>> {
+      if (mode != "link") {
+        diagnostic::error("unsupported pagination mode: `{}`", mode)
+          .primary(*expr)
+          .hint("`paginate` must be `\"link\"` or a lambda")
+          .emit(ctx);
